const d = $json;
const esc = (s) => (s ?? '').replace(/'/g, "''");
const source_ref = `${d.rule_id}:${d.occurrence_date}`;
return [{ json: {
  source_ref,
  title_sql: `'${esc(d.title)}'`,
  consequence_sql: d.consequence ? `'${esc(d.consequence)}'` : 'NULL',
  detail_sql: d.detail ? `'${esc(d.detail)}'` : 'NULL',
  deadline_sql: `'${d.occurrence_date}'`,
  lead_days: d.lead_days,
  urgency_sql: `'${esc(d.urgency)}'`,
  owner_sql: `'${esc(d.owner)}'`,
} }];
